import React from 'react';
import ReactDOM from "react-dom";
import http from "./http-common";
import Accordion from 'react-bootstrap/Accordion';
//import "./styles.css";

class MultiFilters extends React.Component {
  // State with list of all checked item

  constructor(props) {
    super(props);
    this.state = {
      checked: [],
      checkList: props.checkList,
      checkedItems: ""
    }
    //const [checked, setChecked] = useState([]);

    //this.checkList = ["Apple", "Banana", "Tea", "Coffee"];
    this.handleCheck = this.handleCheck.bind(this);
    this.retrieveData = this.retrieveData.bind(this);
  }

  handleCheck(event) {

    //if(this.state.checkList.indexOf(event.target.value) > -1){
    //   const checkListdata = this.state.checkList;
    //  checkListdata.push(event.target.value);
    //  this.setState({checkList: checkListdata, checkedItems: event.target.value});
    //}
    let checkListdata = [];
    let found = false;
    this.state.checked.forEach((checkitem) => {
      if (checkitem != event.target.value) {
        checkListdata.push(checkitem)
      } else {
        found = true;
      }


    });
    if (!found) {
      checkListdata.push(event.target.value);
    }



    this.setState({ checked: checkListdata, checkedItems: checkListdata.join(", ") });
    this.props.parentCallback(checkListdata);
    //  this.setState({ checkedItems: })
  }

  retrieveData() {
    const url = '/contacts.php?action=get_product_category'

    const { page } = this.state;
    let params = { field: this.props.field };

    http.get(url, { params }).then(response => response.data)
      .then((data) => {
        this.setState({ checkList: data })

      })
  }

  componentDidMount() {
    // this.retrieveData();

  }

  render() {
    
      return (

        <div className="app list-container">
          {Object.entries(this.props.checkList).map((mainkey, index) => (
            mainkey[0] !== '' && mainkey[1] !== '' ? (
            <div className="" key={index}>
              <Accordion key={index} >
                <Accordion.Item eventKey="{index}" >
                  <div className="accordion-box maintitle">
                    {mainkey[0]}
                    {mainkey[1] != 0 && <Accordion.Header>
                    </Accordion.Header>
                    }
                  </div>
                  {mainkey[1] != 0 &&
                    <Accordion.Body className="mainfilterbody">

                      <div className="">

                        {Object.entries(mainkey[1]).map((keyname, index) => (

                          <div key={index}>
                            <Accordion >
                              <Accordion.Item eventKey="{index}" >
                                <div className="accordion-box">
                                  <label className="container-checkbox">{keyname[0]}
                                    <input className="checker" value={keyname[0]} type="checkbox" onChange={this.handleCheck} />
                                    <span className="listing-checkbox header checkmark"></span>
                                  </label>
                                  <Accordion.Header>
                                  </Accordion.Header>

                                </div>

                                <Accordion.Body className="childbodylist">


                                  {Object.entries(keyname[1]).map((childkey, index) => (
                                    <div className="sidebar_body" key={index}>
                                      <label className="stm-option-label container-checkbox">{childkey[0]}  ({childkey[1]})
                                        <input className="checker" value={childkey[0]} type="checkbox" onChange={this.handleCheck} />
                                        <span className="listing-checkbox checkmark"></span>
                                      </label>
                                    </div>
                                  ))}
                                </Accordion.Body>

                              </Accordion.Item>
                            </Accordion>
                          </div>
                        ))}

                      </div>
                    </Accordion.Body>
                  }
                </Accordion.Item>
              </Accordion>
            </div>
            ) : null
          ))}
        </div>
      );
  }
}
export default MultiFilters;